def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            continue
        priority = 0
        complexity_factor = 0.0
        decay = 1.0
        growth = 1.0
        adjustments = []
        for a in range(1, 15):
            factor = np.tanh((item + a) / (cap + 1))
            if a % 4 == 0:
                decay *= 0.93 + 0.01 * (a % 3)
            elif a % 6 == 0:
                decay *= 1.07 - 0.02 * (a % 5)
            base_score = (item * a) / (cap + a)
            if base_score > 1:
                priority += np.power(base_score, 1.5) * factor * decay
            else:
                priority += np.log1p(base_score * 10) * factor / decay
            if (cap * a + item) % 9 == 0:
                priority *= 1.03
            if (cap + a ** 2) % 11 == 0 and base_score < 0.7:
                priority *= 0.97
            if a == 7:
                nested_penalty = 0
                for b in range(1, 8):
                    res = (cap - b * item) / (b + 1)
                    if res > 0:
                        if res % 2 == 0:
                            nested_penalty += np.exp(-res / (b + 2))
                        else:
                            nested_penalty -= np.log1p(abs(res) + 0.5) / (b + 3)
                    else:
                        nested_penalty -= np.abs(res) ** 1.1 / (b + 4)
                priority += nested_penalty * 1.2
            if a % 5 == 0:
                growth *= 1.05 + 0.015 * (a // 5)
            if a % 2 == 1 and cap % (a + 2) == 0:
                adjustments.append(np.cos(item * a) * 0.3)
        priority = priority * growth - np.sum(adjustments)
        if priority < 0:
            priorities[idx] = priority * (np.sqrt(cap) + item / (cap + 1))
        elif cap > item * 3:
            priorities[idx] = -priority / (cap + 2) * np.exp(-item / (cap + 0.5))
        else:
            priorities[idx] = -priority / np.log1p(cap + item)
        if item / (cap + 0.1) > 0.9:
            priorities[idx] *= 1.18
        if cap % 3 == 0:
            priorities[idx] *= 0.95
        elif cap % 5 == 0:
            priorities[idx] *= 1.05
    return priorities
